/*buttons inside the action-panel*/
ntx-action-panel button {
    background-color: #FFD700 !important;
    color: #000000 !important;
    font-weight: bold !important;
    border: none !important;
    border-radius: 6px !important;
}

/* Wider Form */
@media screen and (min-width: 0) {
    .nx-form {
        width:100%;
        padding: 20px 15px
    }
}
 
@media screen and (min-width: 768px) {
    .nx-form {
        width:100%;
        padding: 20px 15px
    }
}
 
@media screen and (min-width: 940px) {
    .nx-form {
        width:900px;
        padding: 20px 15px;
    }
}
 
@media screen and (min-width: 1280px) {
    .nx-form {
        width:1200px;
        padding: 25px 15px;
        max-width: 1200px;
    }
}

@media print {
  /* Reduce overall font size */
  body, .ntx-form, .ntx-form * {
    font-size: 10px !important;
    line-height: 1.2 !important;
  }

  /* Shrink field containers and remove excess padding */
  .ntx-form-control,
  .ntx-repeating-section-row,
  .ntx-form-row,
  .ntx-form-section {
    padding: 2px 4px !important;
    margin-bottom: 2px !important;
    min-height: unset !important;
  }

  /* Collapse input fields height */
  input, textarea, select,
  .ntx-form-control input,
  .ntx-form-control textarea {
    height: auto !important;
    min-height: unset !important;
    padding: 1px 4px !important;
  }

  /* Remove large header/banner areas if present */
  .ntx-form-header,
  .ntx-form-footer,
  .ntx-form-actions {
    display: none !important;
  }

  /* Tighten repeating section rows */
  .ntx-repeating-section-row {
    page-break-inside: avoid;
  }

  /* Scale the whole form down */
  .ntx-form {
    transform: scale(0.85);
    transform-origin: top left;
    width: 117% !important;
  }
}
